def a(n):
    s = str(n)
    if len(s) < 2: return n
    res = []
    for i in range(len(s) - 1):
        d1, d2 = int(s[i]), int(s[i+1])
        res.append(s[i])
        res.append(str((d1 + d2) % 10))
    res.append(s[-1])
